function openEditStudentModal(idx) {
    const student = leaderboardDatabase[idx];
    if (!student) return;

    document.getElementById('edit-student-index').value = idx;
    document.getElementById('edit-student-name').value = student.name || '';
    document.getElementById('edit-student-nickname').value = student.nickname || '';
    document.getElementById('edit-student-sid').value = student.studentId || '';
    document.getElementById('edit-student-gender').value = student.gender || '';
    document.getElementById('edit-student-number').value = student.studentNumber || '';
    document.getElementById('edit-student-class').value = student.class || 'm3';
    document.getElementById('edit-student-phone').value = student.phone || '';
    document.getElementById('edit-student-password').value = student.password || '1234';
    document.getElementById('edit-student-email').value = student.email || '';
    document.getElementById('edit-student-score').value = student.score || 0;

    const roomSelect = document.getElementById('edit-student-room');
    populateRoomSelect(roomSelect, student.class, student.room);

    document.getElementById('editStudentModal').style.display = 'flex';
}

function closeEditStudentModal() {
    document.getElementById('editStudentModal').style.display = 'none';
}

function saveEditedStudent() {
    const idx = parseInt(document.getElementById('edit-student-index').value);
    const student = leaderboardDatabase[idx];
    if (!student) return;

    const name = document.getElementById('edit-student-name').value.trim();
    const classVal = document.getElementById('edit-student-class').value;
    const room = document.getElementById('edit-student-room').value;
    const password = document.getElementById('edit-student-password').value.trim();

    if (!name) {
        showToast('กรุณากรอกข้อมูล', 'กรุณาระบุชื่อ-นามสกุลของนักเรียน', 'error');
        return;
    }
    if (!room) {
        showToast('กรุณากรอกข้อมูล', 'กรุณาเลือกห้องของนักเรียน', 'error');
        return;
    }
    if (!password) {
        showToast('กรุณากรอกข้อมูล', 'กรุณาระบุรหัสผ่านเข้าใช้งาน 4 หลัก', 'error');
        return;
    }
    if (password.length !== 4 || !/^\d{4}$/.test(password)) {
        showToast('รูปแบบไม่ถูกต้อง', 'รหัสผ่านต้องเป็นตัวเลข 4 หลักเท่านั้น', 'error');
        return;
    }

    student.name = name;
    student.nickname = document.getElementById('edit-student-nickname').value.trim() || null;
    student.studentId = document.getElementById('edit-student-sid').value.trim() || null;
    student.gender = document.getElementById('edit-student-gender').value || null;
    student.studentNumber = parseInt(document.getElementById('edit-student-number').value) || null;
    student.class = classVal;
    student.room = room;
    student.phone = document.getElementById('edit-student-phone').value.trim() || null;
    student.password = password;
    student.email = document.getElementById('edit-student-email').value.trim() || null;
    student.score = parseInt(document.getElementById('edit-student-score').value) || 0;

    saveAndSyncStudentData();
    closeEditStudentModal();
    renderStudentList();
    updateClassLeaderboardUI();
    updateStudentStatCards();

    showToast('บันทึกสำเร็จ', `อัปเดตข้อมูลของ "${name}" เรียบร้อยแล้ว`, 'success');
}

